  1→//! Centralized setup/teardown lifecycle management.
  2→//!
  3→//! Manages four-level setup lifecycle (session → file → function → execution)
  4→//! with per-level timeouts, failure tracking, and context caching. The
  5→//! `SetupManager` tracks which levels have been initialized and supports
  6→//! skipping setup when a prior failure at a higher level makes it pointless.
  7→
  8→use std::collections::HashMap;
  9→use std::time::Duration;
 10→
 11→use crate::protocol::SetupLevel;
 12→
 13→// ---------------------------------------------------------------------------
 14→// Timeout constants
 15→// ---------------------------------------------------------------------------
 16→
 17→/// Default timeout for session-level setup/teardown.
 18→pub const DEFAULT_SESSION_TIMEOUT: Duration = Duration::from_secs(120);
 19→
 20→/// Default timeout for file-level setup/teardown.
 21→pub const DEFAULT_FILE_TIMEOUT: Duration = Duration::from_secs(30);
 22→
 23→/// Default timeout for function-level setup/teardown.
 24→pub const DEFAULT_FUNCTION_TIMEOUT: Duration = Duration::from_secs(15);
 25→
 26→/// Default timeout for execution-level setup/teardown.
 27→pub const DEFAULT_EXECUTION_TIMEOUT: Duration = Duration::from_secs(5);
 28→
 29→/// Environment variable to override all setup timeouts (value in seconds).
 30→pub const SETUP_TIMEOUT_ENV_VAR: &str = "SHATTER_SETUP_TIMEOUT";
 31→
 32→// ---------------------------------------------------------------------------
 33→// SetupTimeouts
 34→// ---------------------------------------------------------------------------
 35→
 36→/// Per-level timeout configuration for setup/teardown operations.
 37→#[derive(Debug, Clone, PartialEq, Eq)]
 38→pub struct SetupTimeouts {
 39→    pub session: Duration,
 40→    pub file: Duration,
 41→    pub function: Duration,
 42→    pub execution: Duration,
 43→}
 44→
 45→impl Default for SetupTimeouts {
 46→    fn default() -> Self {
 47→        Self {
 48→            session: DEFAULT_SESSION_TIMEOUT,
 49→            file: DEFAULT_FILE_TIMEOUT,
 50→            function: DEFAULT_FUNCTION_TIMEOUT,
 51→            execution: DEFAULT_EXECUTION_TIMEOUT,
 52→        }
 53→    }
 54→}
 55→
 56→impl SetupTimeouts {
 57→    /// Create timeouts from environment, falling back to defaults.
 58→    ///
 59→    /// If `SHATTER_SETUP_TIMEOUT` is set to a valid positive integer, all
 60→    /// levels use that value. Invalid or non-positive values are silently ignored.
 61→    pub fn from_env() -> Self {
 62→        match std::env::var(SETUP_TIMEOUT_ENV_VAR) {
 63→            Ok(val) => match val.parse::<u64>() {
 64→                Ok(secs) if secs > 0 => {
 65→                    let d = Duration::from_secs(secs);
 66→                    Self {
 67→                        session: d,
 68→                        file: d,
 69→                        function: d,
 70→                        execution: d,
 71→                    }
 72→                }
 73→                _ => Self::default(),
 74→            },
 75→            Err(_) => Self::default(),
 76→        }
 77→    }
 78→
 79→    /// Get the timeout for a specific level.
 80→    pub fn timeout_for(&self, level: SetupLevel) -> Duration {
 81→        match level {
 82→            SetupLevel::Session => self.session,
 83→            SetupLevel::File => self.file,
 84→            SetupLevel::Function => self.function,
 85→            SetupLevel::Execution => self.execution,
 86→        }
 87→    }
 88→}
 89→
 90→// ---------------------------------------------------------------------------
 91→// SetupFailures
 92→// ---------------------------------------------------------------------------
 93→
 94→/// Tracks which setup levels have failed, preventing cascading setup attempts
 95→/// at dependent (inner) levels.
 96→#[derive(Debug, Clone, Default)]
 97→pub struct SetupFailures {
 98→    failures: HashMap<SetupLevel, String>,
 99→}
100→
101→impl SetupFailures {
102→    /// Record a failure at the given level with an error description.
103→    pub fn record(&mut self, level: SetupLevel, error: String) {
104→        self.failures.insert(level, error);
105→    }
106→
107→    /// Clear the failure for a given level (e.g., after successful retry).
108→    pub fn clear(&mut self, level: SetupLevel) {
109→        self.failures.remove(&level);
110→    }
111→
112→    /// Check if a specific level has failed.
113→    pub fn has_failed(&self, level: SetupLevel) -> bool {
114→        self.failures.contains_key(&level)
115→    }
116→
117→    /// Get the error message for a failed level.
118→    pub fn error_for(&self, level: SetupLevel) -> Option<&str> {
119→        self.failures.get(&level).map(|s| s.as_str())
120→    }
121→}
122→
123→// ---------------------------------------------------------------------------
124→// SetupError
125→// ---------------------------------------------------------------------------
126→
127→/// Errors from setup/teardown operations.
128→#[derive(Debug, thiserror::Error)]
129→pub enum SetupError {
130→    #[error("setup timed out at {level:?} level after {timeout:?}")]
131→    Timeout {
132→        level: SetupLevel,
133→        timeout: Duration,
134→    },
135→
136→    #[error("setup failed at {level:?} level: {message}")]
137→    Failed {
138→        level: SetupLevel,
139→        message: String,
140→    },
141→
142→    #[error("setup skipped at {level:?} level due to prior failure at {cause_level:?}")]
143→    Skipped {
144→        level: SetupLevel,
145→        cause_level: SetupLevel,
146→    },
147→}
148→
149→// ---------------------------------------------------------------------------
150→// SetupManager
151→// ---------------------------------------------------------------------------
152→
153→/// Context value returned by a frontend's setup command.
154→pub type SetupContext = serde_json::Value;
155→
156→/// Centralizes setup lifecycle across all four levels.
157→///
158→/// Caches context values returned by setup commands so teardown can reference
159→/// them, and tracks failures to enable `should_skip` decisions.
160→#[derive(Debug, Clone)]
161→pub struct SetupManager {
162→    /// Cached context per level. Key is (level, scope) where scope is a
163→    /// distinguishing string (e.g., file path for File level, function name
164→    /// for Function level). Session level uses an empty scope.
165→    contexts: HashMap<(SetupLevel, String), SetupContext>,
166→
167→    /// Tracks which levels have failed.
168→    pub failures: SetupFailures,
169→
170→    /// Per-level timeouts.
171→    pub timeouts: SetupTimeouts,
172→
173→    /// When true, a setup failure at any level is fatal (returns error).
174→    /// When false, failures are recorded but exploration continues.
175→    pub fail_on_error: bool,
176→}
177→
178→impl SetupManager {
179→    /// Create a new SetupManager with the given timeouts and fail_on_error policy.
180→    pub fn new(timeouts: SetupTimeouts, fail_on_error: bool) -> Self {
181→        Self {
182→            contexts: HashMap::new(),
183→            failures: SetupFailures::default(),
184→            timeouts,
185→            fail_on_error,
186→        }
187→    }
188→
189→    /// Create with default timeouts (respecting env var) and fail_on_error = false.
190→    pub fn from_env() -> Self {
191→        Self::new(SetupTimeouts::from_env(), false)
192→    }
193→
194→    /// Record a successful setup at the given level and scope, caching its context.
195→    pub fn setup(
196→        &mut self,
197→        level: SetupLevel,
198→        scope: &str,
199→        context: SetupContext,
200→    ) -> Result<(), SetupError> {
201→        if let Some(cause_level) = self.blocking_failure(level) {
202→            return Err(SetupError::Skipped {
203→                level,
204→                cause_level,
205→            });
206→        }
207→        self.contexts
208→            .insert((level, scope.to_string()), context);
209→        self.failures.clear(level);
210→        Ok(())
211→    }
212→
213→    /// Record a setup failure at the given level.
214→    pub fn record_failure(
215→        &mut self,
216→        level: SetupLevel,
217→        error: String,
218→    ) -> Result<(), SetupError> {
219→        self.failures.record(level, error.clone());
220→        if self.fail_on_error {
221→            Err(SetupError::Failed {
222→                level,
223→                message: error,
224→            })
225→        } else {
226→            Ok(())
227→        }
228→    }
229→
230→    /// Remove the context for the given level and scope (teardown completed).
231→    pub fn teardown(&mut self, level: SetupLevel, scope: &str) {
232→        self.contexts.remove(&(level, scope.to_string()));
233→    }
234→
235→    /// Get the cached context for a specific level and scope.
236→    pub fn get_context(&self, level: SetupLevel, scope: &str) -> Option<&SetupContext> {
237→        self.contexts.get(&(level, scope.to_string()))
238→    }
239→
240→    /// Build a context stack from outermost (session) to innermost, collecting
241→    /// all active contexts for the given scopes.
242→    ///
243→    /// `scopes` should be ordered from session to execution, e.g.:
244→    /// `["", "src/auth.ts", "validateToken", "exec-0"]`
245→    pub fn context_stack(&self, scopes: &[(SetupLevel, &str)]) -> Vec<(SetupLevel, &SetupContext)> {
246→        let level_order = [
247→            SetupLevel::Session,
248→            SetupLevel::File,
249→            SetupLevel::Function,
250→            SetupLevel::Execution,
251→        ];
252→
253→        let mut stack = Vec::new();
254→        for &level in &level_order {
255→            if let Some((_, scope)) = scopes.iter().find(|(l, _)| *l == level)
256→                && let Some(ctx) = self.get_context(level, scope)
257→            {
258→                stack.push((level, ctx));
259→            }
260→        }
261→        stack
262→    }
263→
264→    /// Check whether setup at the given level should be skipped due to a
265→    /// prior failure at the same or an outer level.
266→    pub fn should_skip(&self, level: SetupLevel) -> bool {
267→        self.blocking_failure_inclusive(level).is_some()
268→    }
269→
270→    /// Find the outermost failed level that blocks the given level (inclusive).
271→    /// Used by `should_skip` — includes the same level.
272→    fn blocking_failure_inclusive(&self, level: SetupLevel) -> Option<SetupLevel> {
273→        let hierarchy = [
274→            SetupLevel::Session,
275→            SetupLevel::File,
276→            SetupLevel::Function,
277→            SetupLevel::Execution,
278→        ];
279→
280→        let target_idx = hierarchy.iter().position(|l| *l == level).unwrap_or(0);
281→        hierarchy[..=target_idx]
282→            .iter()
283→            .find(|l| self.failures.has_failed(**l))
284→            .copied()
285→    }
286→
287→    /// Find a failed outer level that prevents setup at the given level.
288→    /// Excludes the same level so retry is allowed.
289→    fn blocking_failure(&self, level: SetupLevel) -> Option<SetupLevel> {
290→        let hierarchy = [
291→            SetupLevel::Session,
292→            SetupLevel::File,
293→            SetupLevel::Function,
294→            SetupLevel::Execution,
295→        ];
296→
297→        let target_idx = hierarchy.iter().position(|l| *l == level).unwrap_or(0);
298→        hierarchy[..target_idx]
299→            .iter()
300→            .find(|l| self.failures.has_failed(**l))
301→            .copied()
302→    }
303→
304→    /// Number of active (cached) contexts across all levels.
305→    pub fn active_context_count(&self) -> usize {
306→        self.contexts.len()
307→    }
308→}
