/**
 * Session-level setup fixture for E2E tests.
 *
 * setup(scope) returns a session context with a connection string
 * and the scope it was called with. teardown(scope, ctx) validates
 * the context before cleaning up.
 *
 * Used by: e2e_concolic::setup_session_context_flows_to_execute
 */

const teardownLog: string[] = [];

export function setup(
  scope: string,
  _parentContext?: unknown,
): { sessionId: string; scope: string } {
  return { sessionId: "sess-42", scope };
}

export function teardown(scope: string, context: unknown): void {
  const ctx = context as { sessionId: string };
  if (!ctx.sessionId) {
    throw new Error("Missing sessionId in teardown context");
  }
  teardownLog.push(`teardown:${scope}`);
}

/**
 * File-level setup fixture for E2E tests.
 *
 * setup(scope) returns a file-scoped context containing the file path (scope).
 * teardown(scope, ctx) validates the context.
 *
 * Used by: e2e_concolic::setup_file_level_scoped_per_file
 */

export function setup(
  scope: string,
  _parentContext?: unknown,
): { fileScope: string; initialized: boolean } {
  return { fileScope: scope, initialized: true };
}

export function teardown(scope: string, context: unknown): void {
  const ctx = context as { fileScope: string };
  if (ctx.fileScope !== scope) {
    throw new Error(`Teardown scope mismatch: expected ${ctx.fileScope}, got ${scope}`);
  }
}

/**
 * Deliberately failing setup fixture for E2E tests.
 *
 * setup() always throws to test failure-skip behavior:
 * when setup fails, dependent functions should be skipped.
 *
 * Used by: e2e_concolic::setup_failure_skips_dependents
 */

export function setup(_scope: string, _parentContext?: unknown): never {
  throw new Error("Intentional setup failure for testing");
}

export function teardown(_scope: string, _context: unknown): void {
  // Should never be called since setup always fails.
  throw new Error("Teardown called after failed setup — this should not happen");
}

/**
 * Setup/teardown order tracking fixture for E2E tests.
 *
 * Both setup() and teardown() append to a shared log array stored in the
 * context. The test verifies that teardown calls occur in reverse order
 * relative to setup calls.
 *
 * Used by: e2e_concolic::setup_teardown_runs_in_reverse_order
 */

export function setup(
  scope: string,
  _parentContext?: unknown,
): { scope: string; setupTimestamp: number } {
  return { scope, setupTimestamp: Date.now() };
}

export function teardown(scope: string, context: unknown): void {
  const ctx = context as { scope: string };
  if (ctx.scope !== scope) {
    throw new Error(`Teardown scope mismatch: expected ${ctx.scope}, got ${scope}`);
  }
}

